INSERT INTO compliance_rules (framework_short,rule_id,description,regex_pattern,url_check,severity,citation_url,enforcement_example,rule_type,trigger_pattern,fine_low_gbp,fine_high_gbp,layman_explanation,tamazia_fix_short,service_page_path,pricing_tier,active,sector_relevance,created_at) VALUES
('UK_PECR','PECR_REJECT_ALL_PARITY','Cookie banner must offer a Reject-All / non-essential-refusal option as prominent and functional as Accept-All','(reject all|reject non[- ]essential|decline all|refuse all|reject cookies|necessary (cookies )?only|only essential|manage preferences)','homepage','P1','https://ico.org.uk/for-organisations/direct-marketing-and-privacy-and-electronic-communications/guide-to-pecr/cookies-and-similar-technologies/','DUAA 2025 raised the maximum PECR fine from 500000 to 17.5M or 4 percent of global turnover. The ICO is sweeping the top 1000 UK sites; in its first batch of 200, 134 firms were warned and given 30 days to fix non-compliant banners.','trigger_then_check','(cookie|cookies|consent|gdpr|privacy preferences|manage cookies|we use cookies)',2000,17500000,'Your cookie banner needs a Reject All button that is just as easy to find and click as Accept All, and it must actually stop non-essential cookies. A reject button that does nothing is treated as worse than none.','Install a compliant consent platform with an equally prominent, functional Reject All that blocks non-essential tags until consent.','/services/compliance','growth',TRUE,NULL,now()),
('UK_PECR','PECR_CONSENT_PLATFORM','Marketing or analytics trackers present but no consent-management platform gating them before consent','(cookiebot|onetrust|cookieyes|usercentrics|termly|consent ?manager|cookie consent|iubenda|complianz|quantcast|cookie ?control|civic ?cookie)','homepage','P1','https://ico.org.uk/for-organisations/direct-marketing-and-privacy-and-electronic-communications/guide-to-pecr/cookies-and-similar-technologies/','Both the SHEIN and American Express PECR cases involved cookies being set despite users clicking Reject All. The ICO treats non-functional or absent consent gating on analytics and advertising trackers as a consent violation.','trigger_then_check','(gtag|google-analytics|googletagmanager|fbq|facebook pixel|hotjar|doubleclick|linkedin insight|tiktok pixel|_ga|clarity\.ms)',2000,17500000,'You are running Google, Meta or other tracking pixels but there is no consent tool stopping them before the visitor agrees. Those trackers fire on load, which breaks PECR.','Deploy a consent platform in blocking mode so analytics and ad tags load only after opt-in.','/services/compliance','growth',TRUE,NULL,now()),
('UK_DMCC_2024','DMCC_INCENTIVISED_REVIEWS','Reviews or testimonials shown without disclosing incentives or a genuine-review verification process','(incentivi|in exchange for|gifted|sponsored|disclosure|we verify|verified (review|purchase)|independently collected|genuine review|honest review)','homepage','P1','https://www.gov.uk/government/publications/dmcc-act-unfair-commercial-practices-guidance','The DMCC Act fake-review ban came into force on 6 April 2025; the CMA began enforcement from July 2025 and can fine up to 10 percent of global annual turnover without going to court. Businesses have a positive duty to prevent and remove fake and undisclosed-incentivised reviews.','trigger_then_check','(review|reviews|testimonial|rated|star rating|trustpilot|google reviews|[1-5](\.\d)? ?stars?|customer feedback|what our (clients|customers) say)',10000,300000,'If you display reviews or testimonials, you must not feature fake ones and must disclose any that were incentivised or gifted. The CMA can fine up to 10 percent of worldwide turnover.','Add review-verification and an incentive-disclosure process, and remove any testimonials you cannot substantiate.','/services/compliance','growth',TRUE,NULL,now()),
('EU_EAA_2025','EAA_WCAG_AA','Consumer-facing digital service serving the EU with no evident WCAG 2.1 AA accessibility conformance','(accessibility|wcag|aria-|alt=|skip to (content|main)|screen reader|en 301 ?549|accessibility statement)','homepage','P1','https://eur-lex.europa.eu/legal-content/EN/TXT/?uri=CELEX%3A32019L0882','European Accessibility Act enforcement powers became active on 28 June 2025. The benchmark is WCAG 2.1 AA via EN 301 549. Germany fines up to 100000 euros per violation, France 5000 to 250000 euros plus 25000 euros a year for a missing accessibility statement, and Spain up to 300000 euros.','trigger_then_check','(add to (cart|basket)|checkout|buy now|book (now|online)|create (an )?account|sign ?up|online (banking|store|shop|booking)|e-?commerce|subscribe|place order)',4300,258000,'If you sell or take bookings online to EU customers, the site must meet WCAG 2.1 AA accessibility and publish an accessibility statement. Several EU states are now fining non-compliant services.','Run a WCAG 2.1 AA audit, fix contrast, keyboard, alt-text and labelling gaps, and publish an accessibility statement.','/services/compliance','scale',TRUE,NULL,now()),
('US_FTC_ENDORSE','FTC_CONSUMER_REVIEW_RULE','Reviews or testimonials shown to US consumers without genuine-review safeguards under the FTC Consumer Review Rule','(verified (review|purchase)|genuine review|honest review|we do not (buy|incentivi)|disclosure|material connection|independently verified)','homepage','P1','https://www.ftc.gov/business-guidance/resources/consumer-reviews-testimonials-rule-questions-answers','The FTC Consumer Reviews and Testimonials Rule took effect on 21 October 2024 with civil penalties of 53088 dollars per violation. On 22 December 2025 the FTC issued its first warning letters to 10 companies under the rule.','trigger_then_check','(review|reviews|testimonial|rated|star rating|[1-5](\.\d)? ?stars?|customer feedback|what our (clients|customers) say)',42000,200000,'If you show reviews or testimonials to US customers, fake, undisclosed-incentivised, or suppressed-negative reviews now carry an FTC penalty of 53088 dollars each.','Implement an FTC-compliant review process: no fabricated or undisclosed-incentivised reviews, no suppression of genuine negatives.','/services/compliance','scale',TRUE,NULL,now()),
('US_FTC_ENDORSE','FTC_MATERIAL_CONNECTION','Endorsements, ambassador or affiliate content without a clear material-connection disclosure','(#ad|#sponsored|paid partnership|material connection|disclosure|compensated|affiliate (link|disclosure)|we (may )?earn)','homepage','P2','https://www.ftc.gov/business-guidance/resources/ftcs-endorsement-guides-what-people-are-asking','The FTC Endorsement Guides (updated 2023) require clear and conspicuous disclosure of any material connection between an endorser and the brand. Undisclosed paid endorsements draw FTC action.','trigger_then_check','(testimonial|endorse|brand ambassador|influencer|affiliate|as seen (on|in)|sponsored|partner(ed)? with)',42000,200000,'Any paid, gifted or affiliate endorsement must say so clearly. Hidden material connections breach the FTC Endorsement Guides.','Add clear and conspicuous disclosures to all endorsement, ambassador and affiliate content.','/services/compliance','scale',TRUE,NULL,now()),
('US_CPRA','CPRA_DO_NOT_SELL','Personal data sold or shared for advertising with no Do Not Sell or Share opt-out link','(do not sell|do not share|your privacy choices|opt[- ]out of (the )?(sale|sharing)|limit the use of (my|your) sensitive)','homepage','P1','https://oag.ca.gov/privacy/ccpa','Under CCPA as amended by CPRA, selling or sharing personal information for cross-context advertising without a Do Not Sell or Share My Personal Information link carries 2500 dollars per violation, rising to 7500 dollars for intentional violations or minors.','trigger_then_check','(third[- ]party (advertis|cookies)|targeted ad|sell your|share your (data|information)|data partners|marketing partners|advertising partners|google ads|meta pixel)',2000,6000,'If you share data with ad networks and serve California users, you must show a Do Not Sell or Share My Personal Information link and honor it.','Add a compliant Do Not Sell or Share link wired to opt-out signals including Global Privacy Control.','/services/compliance','scale',TRUE,NULL,now()),
('US_TCPA','TCPA_SMS_CONSENT','SMS or text marketing collected without prior express written consent and required disclosures','(prior express written consent|consent to receive|msg ?& ?data rates( may apply)?|message and data rates|reply stop|standard message rates|opt[- ]in)','homepage','P2','https://www.fcc.gov/general/telemarketing-and-robocalls','The TCPA requires prior express written consent for marketing texts, with statutory damages of 500 to 1500 dollars per message. The FCC one-to-one consent rules tightened lead-consent requirements.','trigger_then_check','(text (us|message)|sms (alerts|updates)|by texting|subscribe.*text|join.*text|sign up.*sms)',395,1185,'If you collect phone numbers for marketing texts to US contacts, you need express written consent and clear opt-out and rate disclosures, or face 500 to 1500 dollars per text.','Add TCPA-compliant SMS consent language, opt-out instructions and rate disclosure to every phone-capture form.','/services/compliance','scale',TRUE,NULL,now()),
('US_ADA','ADA_WEB_ACCESSIBILITY','US public-accommodation website with no evident accessibility conformance under ADA Title III','(accessibility|wcag|aria-|alt=|skip to (content|main)|screen reader|accessibility statement|ada compliant)','homepage','P1','https://www.ada.gov/resources/web-guidance/','DOJ 2024 guidance treats WCAG 2.1 AA as the practical standard for ADA web accessibility. Title III web-accessibility lawsuits run into the thousands each year and DOJ civil penalties reach 75000 dollars for a first violation.','trigger_then_check','(add to (cart|basket)|checkout|buy now|book (now|online|an appointment)|create (an )?account|online (store|shop|booking)|patients?|customers?)',0,59000,'US businesses serving the public are expected to make their websites usable with screen readers and keyboards. Non-compliant sites draw ADA demand letters and lawsuits.','Bring the site to WCAG 2.1 AA and publish an accessibility statement to reduce ADA Title III exposure.','/services/compliance','scale',TRUE,NULL,now()),
('UK_COMPANIES_ACT','CA_TRADING_DISCLOSURE','Incorporated entity not displaying company number, registered office and place of registration on its website','(company (registration )?(no|number)|registered in (england|scotland|wales|northern ireland)|registered office|company no\.?|registered number|incorporated in)','homepage','P2','https://www.legislation.gov.uk/ukdsi/2015/9780111125892/contents','The Companies (Trading Disclosures) Regulations 2015 and Companies Act 2006 s82 require a company to show its registered name, number, place of registration and registered office address on its website. Failure is an offence carrying a 1000 pound fine plus 100 pounds a day.','trigger_then_check','(\bltd\b|limited\b|\bplc\b|\bllp\b|& co\b|company registration|companies house)',1000,1000,'A UK limited company must print its company number, where it is registered and its registered office on the website. Many firms only put the trading name, which is an offence.','Add the full trading-disclosure block (registered name, number, place of registration, registered office) to the footer or contact page.','/services/compliance','starter',TRUE,NULL,now()),
('UK_CRA_2015','CRA_DISTANCE_CANCELLATION','Online sales with no visible 14-day cancellation, returns or refund rights for distance consumers','(14[- ]day|cooling[- ]off|right to cancel|returns? policy|refund policy|cancellation rights|distance selling)','homepage','P2','https://www.legislation.gov.uk/uksi/2013/3134/contents/made','The Consumer Contracts Regulations 2013 give distance-selling consumers a 14-day cancellation right that must be communicated; the Consumer Rights Act 2015 governs refunds. Trading Standards enforce and the DMCC raises consumer-law fines to 10 percent of turnover.','trigger_then_check','(add to (cart|basket)|checkout|buy now|place order|online order|subscribe|purchase online|shop now)',NULL,NULL,'Selling online to UK consumers means you must tell them about their 14-day right to cancel and your returns and refund policy before they buy.','Publish clear cancellation, returns and refund terms and surface them at checkout.','/services/compliance','starter',TRUE,NULL,now()),
('UK_DPA_2018','DPA_ICO_FEE','Organisation processing personal data with no sign of ICO data-protection-fee registration','(registered with the ico|ico registration|data protection fee|ico reference|registration number z|ico registered)','homepage','P3','https://ico.org.uk/for-organisations/data-protection-fee/','Most UK organisations that process personal data must pay the ICO data protection fee of 40 to 2900 pounds and register. The ICO issues monetary penalties up to 4350 pounds for non-payment and publishes defaulters.','trigger_then_check','(contact (us|form)|email us|newsletter|sign ?up|your (data|information)|privacy policy|we collect|personal data)',400,4350,'If you collect any personal data you almost certainly must register and pay the ICO data protection fee. Non-payment is fined and published.','Confirm ICO registration, pay the data protection fee, and reference it in the privacy policy.','/services/compliance','starter',TRUE,NULL,now())
